Rules.InvariantScript:
Patch(CRRequests, gblConsolidationCR, {CRStatus: {Value: "In Assessment"}, PMONotes: txtNotesPCS.Text});
If(IsEmpty(Errors(CRRequests)),
  Set(gblConsolidationCR, Blank());
  Notify("CR accepted and distributed for assessment.", NotificationType.Success),
  Notify("Action failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
)

Patch(CRRequests, gblConsolidationCR, {CRStatus: {Value: "Submitted"}, PMONotes: txtNotesPCS.Text});
If(IsEmpty(Errors(CRRequests)),
  Set(gblConsolidationCR, Blank());
  Notify("CR returned to owner for revision.", NotificationType.Warning),
  Notify("Action failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
)

If(CountRows(Filter(CRStakeholderReviews,
    CRNumber = gblConsolidationCR.CRNumber, RAGStatus.Value = "Pale Blue")) > 0,
  Notify("Cannot proceed — " &
    Text(CountRows(Filter(CRStakeholderReviews, CRNumber = gblConsolidationCR.CRNumber, RAGStatus.Value = "Pale Blue"))) &
    " stakeholder group(s) are still Pale Blue.",
    NotificationType.Error),
  Patch(CRRequests, gblConsolidationCR, {CRStatus: {Value: "Pre-SG Distribution"}, PMONotes: txtNotesPCS.Text});
  If(IsEmpty(Errors(CRRequests)),
    Set(gblConsolidationCR, Blank());
    Notify("CR marked ready for Pre-SG Distribution.", NotificationType.Success),
    Notify("Action failed — " & First(Errors(CRRequests)).Message, NotificationType.Error)
  )
)

